sql:
SELECT DISTINCT domain_name
FROM sites
WHERE site_description LIKE '%forest%' AND elevation > 300;

external_knowledge:
- "larger sites" refers to sites with an area greater than 5000 square meters;
- "specific areas" refers to the subplot identifiers;
- "methods being utilized" refers to the names of the sampling protocols used for the subplots.

sql:
SELECT core_id 
FROM samples 
WHERE root_sample_area = (SELECT MAX(root_sample_area) FROM samples);

external_knowledge:
- 'spot' refers to 'site';
- 'location area' refers to 'domain_name';
- 'quick overview' is synonymous with 'site_description';
- 'geographical position' is described by the latitude and longitude coordinates;
- 'precision of the position' is related to the uncertainty in the coordinate measurement;
- 'height above sea level' is the elevation of the site;
- 'size' refers to the area of the site;
- 'when it first came into being' is synonymous with 'site_establishment_date'.

sql:
SELECT domain_name
FROM sites
WHERE site_area = (SELECT MAX(site_area) FROM sites);

external_knowledge:
- 'places' refers to 'sites';
- 'typical size of the areas they plot' refers to the average plot area of the plots associated with each site;
- 'if a place has no plots, its typical size is zero' means that if there is no data available for the average plot area, the value is set to zero.

sql:
SELECT subplot_id
FROM subplots
WHERE plot_id = '0' AND subplot_number <> 41;

SELECT DISTINCT site_name
FROM sites
WHERE domain_name = 'BART';

SELECT site_name, site_description
FROM sites
WHERE site_area = (
    SELECT MAX(site_area)
    FROM sites
);
